var getSetting = async (key) => {
  try {
    return (await pb.collection('settings').getFirstListItem(`key="${key}"`)).value
  } catch {
    return
  }
}
var upsertSetting = async (key, value) => {
  try {
    const existing = await pb.collection('settings').getFirstListItem(`key="${key}"`)
    return pb.collection('settings').update(existing.id, { value })
  } catch {
    return pb.collection('settings').create({
      key,
      value,
    })
  }
}
